; Applesoft BASIC for HBC-56 - Interpreter
;
; Executes bytecode generated by the tokenizer
;

; Zero page allocations
interp_pc          = $28   ; Program counter in bytecode
interp_sp          = $2A   ; Stack pointer
for_depth          = $2B   ; FOR loop nesting depth
gosub_depth        = $2C   ; GOSUB nesting depth
current_stmt       = $2D   ; Current statement token

; Variable storage area
*=$0200
variable_table:
    !fill 256, 0            ; Variables: max 32 variables

; String pool
*=$0300
string_pool:
    !fill 4096, 0           ; String storage: 4KB

; GOSUB return stack
*=$1300
gosub_stack:
    !fill 64, 0             ; 32 return addresses (2 bytes each)

; FOR loop stack
*=$1340
for_stack:
    !fill 64, 0             ; 16 FOR contexts (4 bytes each)

; User program bytecode
*=$1400
program_buffer:
    !fill 30720, 0          ; User program: ~30KB max

; =============================================================================
; interpret: Main bytecode interpreter loop
; Input:  program_buffer = bytecode
; Output: (program terminates)
; =============================================================================
interpret:
    php
    pha
    phx
    phy
    
    lda #0
    sta for_depth
    sta gosub_depth
    sta interp_pc
    sta interp_pc+1
    
    ; Fetch-decode-execute loop
exec_loop:
    lda (interp_pc)
    
    ; Dispatch on token type (keywords are $00-$0F)
    cmp #$10
    bcs skip_stmt_keyword
    jsr exec_keyword
    bra next_token
skip_stmt_keyword:
    
    ; Handle other token types...
    
    ; Move to next token
next_token:
    inc interp_pc
    bne exec_loop
    inc interp_pc+1
    bra exec_loop
    
exec_keyword:
    rts

; Keyword handler stubs
stmt_print:
    rts

stmt_input:
    rts

stmt_let:
    rts

stmt_goto:
    rts

stmt_if:
    rts

stmt_for:
    rts

stmt_next:
    rts

stmt_gosub:
    rts

stmt_return:
    rts

stmt_rem:
    rts

stmt_end:
    rts
